<template>
  <div class="hello">
    <h1>{{ msg }}</h1>
    <h5>Author:{{author}}</h5>
    <h5>Work_address:{{work_address}}</h5>
    <h5>E-mail:{{email}}</h5>

    <hr/>
    <div id="app-2">
      <span v-bind:title="msg">
        鼠标悬停几秒钟查看此处动态绑定的提示信息!
      </span>
    </div>

    <hr/>
    <div id="app-3">
      <p v-if="seen">
        现在你看到我了
      </p>
    </div>

    <hr/>
    <div id="app-4">
      <ol>
        <li v-for="todo in todos" :key="todo.text">
          {{ todo.text }}
        </li>
      </ol>
    </div>

    <hr/>
    <div id="app-5">
      <p>{{msg}}</p>
      <button v-on:click="reverseMessage">
        逆转消息
      </button>
    </div>

    <hr/>
    <div id="app-6">
      <p>{{msg}}</p>
      <input v-model="msg">
    </div>

    <hr/>
    <div id="app-7">
      <ol>
        <!--
          现在我们为每个todo-item提供todo对象
          todo对象是变量，即其内容可以是动态的。。
          我们也需要为每个组件提供一个"key",稍后再做详细解释
        -->
        <todo-item
          v-for="item in groceryList"
          v-bind:todo="item"
          v-bind:key="item.id"></todo-item>
        <li v-for="todo in groceryList" :key="todo.text">{{ todo.text }}</li>
      </ol>
    </div>

  </div>
</template>

<script>
export default {
  name: 'HelloWorld',
  // 数据提供
  data () {
    return {
      msg: 'Welcome to Your Vue.js App.(nixinsheng)' + new Date().toLocaleString(),
      author: '倪新生',
      work_address: 'BeiJing.CHINA',
      email: '1911398892@qq.com',
      seen: true,
      todos: [
        {text: '1.学习 JavaScript'},
        {text: '2.学习 Vue'},
        {text: '3.整个牛🐂项目'}
      ],
      groceryList: [
        {id: 0, text: '蔬菜'},
        {id: 1, text: '奶酪🧀'},
        {id: 2, text: '随便其他什么人吃的东西'}
      ]
    }
  },
  // 方法提供
  methods: {
    reverseMessage: function () {
      this.msg = this.msg.split('').reverse().join('')
    }
  },
  created: function () {
    // 'this'指向vm实例
    console.log('msg is:' + this.msg)
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
  h1, h2 {
    font-weight: bold;
  }

  ul {
    list-style-type: none;
    padding: 0;
  }

  li {
    display: inline-block;
    margin: 0 10px;
  }

  a {
    color: #42b98F;
  }
</style>



